def unique_paths(m, n):
    def helper(r, c):
        if r == m - 1 or c == n - 1:
            return 1
        return helper(r + 1, c) + helper(r, c + 1)

    return helper(0, 0)

def unique_paths(m, n):
    row = [1] * n
    for _ in range(1, m):
        for c in range(1, n):
            row[c] += row[c - 1]
    return row[-1]
